let data = msg.payload;
if (!data || !data.today_stats) return [null, null, null, null];
let stats   = data.today_stats;
let current = data.current || {};

// v2_today（數值來自 Python tracker）
let todayDate = new Date().toLocaleDateString('zh-TW');
let today = {
    date:              todayDate,
    walk:    { count: Number(stats.walk    || 0), time: Number(stats.walk_time    || 0) },
    lick:    { count: Number(stats.lick    || 0), time: Number(stats.lick_time    || 0) },
    scratch: { count: Number(stats.scratch || 0), time: Number(stats.scratch_time || 0) },
    shake:   { count: Number(stats.shake   || 0), time: Number(stats.shake_time   || 0) },
    stop:    { count: Number(stats.stop    || 0), time: Number(stats.stop_time    || 0) },
    active_time:        Number(stats.active_time        || 0),
    rest_time:          Number(stats.rest_time          || 0),
    not_detected_time:  Number(stats.not_detected_time  || 0),
    monitoring_seconds: Number(stats.monitoring_seconds || 0)
};
global.set('v2_today', today, 'file');

// 轉移矩陣、每小時分布：Python 計算好直接存入 context
global.set('v2_transition_matrix', stats.transition_matrix   || {});
global.set('v2_hourly',            stats.hourly_distribution || {});

// emoji fallback
let emojiMap = {walk:'🚶',lick:'😸',scratch:'🐾',shake:'🔄',stop:'😴',not:'📷'};
if (!current.emoji) current.emoji = emojiMap[current.behavior] || '🐱';

msg.payload           = data;
msg.payload.v2_today  = today;
msg.payload.v2_hourly = stats.hourly_distribution || {};
msg.payload.v2_matrix = stats.transition_matrix   || {};


return [msg, msg, msg, null];

let data = msg.payload;
let td   = data.v2_today || {};
let times = {
    walk:    td.walk    ? td.walk.time    : 0,
    lick:    td.lick    ? td.lick.time    : 0,
    scratch: td.scratch ? td.scratch.time : 0,
    shake:   td.shake   ? td.shake.time   : 0,
    stop:    td.stop    ? td.stop.time    : 0
};
let total = Object.values(times).reduce((a,b)=>a+b, 0);
let dist  = {};
if (total > 0) {
    for (let [k,v] of Object.entries(times)) dist[k] = parseFloat((v/total*100).toFixed(2));
} else {
    dist = {walk:0,lick:0,scratch:0,shake:0,stop:0};
}
flow.set('v2_distribution', dist);
msg.payload.distribution = dist;
return msg;

let data   = msg.payload;
let hourly = data.v2_hourly || {};
let periods = {
    '00-06': {walk:0,lick:0,scratch:0,shake:0,stop:0,total:0},
    '06-12': {walk:0,lick:0,scratch:0,shake:0,stop:0,total:0},
    '12-18': {walk:0,lick:0,scratch:0,shake:0,stop:0,total:0},
    '18-24': {walk:0,lick:0,scratch:0,shake:0,stop:0,total:0}
};
for (let h=0; h<24; h++) {
    let k  = String(h).padStart(2,'0');
    let hd = hourly[k] || {};
    let pd = h<6?'00-06':h<12?'06-12':h<18?'12-18':'18-24';
    let bs = ['walk','lick','scratch','shake','stop'];
    for (let b of bs) {
        let v = hd[b] || 0;
        periods[pd][b]     += v;
        periods[pd].total  += v;
    }
}
let rhythm = {};
for (let [pd, d] of Object.entries(periods)) {
    if (d.total === 0) { rhythm[pd] = {dominant:'none',pct:{},total:0}; continue; } // 'none' = 該時段無任何行為資料（未監控或貓始終不在畫面）
    let bs  = ['walk','lick','scratch','shake','stop'];
    let dom = bs.reduce((a,b) => d[a]>=d[b]?a:b, 'stop'); // 該時段佔時間最長的行為
    let pct = {}; // 各行為佔該時段總秒數的百分比
    for (let b of bs) pct[b] = parseFloat((d[b]/d.total*100).toFixed(2));
    rhythm[pd] = {dominant:dom, pct, total:parseFloat(d.total.toFixed(1))};
}
flow.set('v2_rhythm', rhythm);
msg.payload.rhythm = rhythm;
return msg;

// ══════════════════════════════════════════════════════════════
//  統計偏差分析引擎 v3.0
//  完全移除固定百分比門檻，改用統計異常判斷
//  每個指標輸出: today, mean, median, std, rolling_mean,
//               z_score, robust_z, percentile, deviation_score
// ══════════════════════════════════════════════════════════════

let data = msg.payload;
let td   = data.v2_today || {};
let bl;
try { bl = global.get('v2_baseline','file') || global.get('v2_baseline'); }
catch(e) { bl = global.get('v2_baseline'); }

if (!bl || !bl.metrics) {
    msg.payload.deviation           = null;
    msg.payload.deviation_available = false;
    return msg;
}

let m  = bl.metrics;
let l2 = bl.layer2 || {};
let l1 = bl.layer1 || {};

// 鍵名對應表：metrics key → layer2/layer1 完整統計物件
const L2_MAP = {
    lick_time:     'lick_duration',
    lick_count:    'lick_frequency',
    scratch_time:  'scratch_duration',
    scratch_count: 'scratch_frequency',
    shake_count:   'head_shake_frequency'
};
const L1_MAP = {
    walk_time: 'walk_duration',
    stop_time: 'inactive_duration'
};

function getStats(key) {
    let l2key = L2_MAP[key];
    let l1key = L1_MAP[key];
    if (l2key && l2[l2key]) return l2[l2key];
    if (l1key && l1[l1key]) return l1[l1key];
    return m[key] || {};
}

// Z-score：(今日值 − 歷史均值) / 歷史標準差
function calcZScore(cur, key) {
    let s = getStats(key);
    if (!s || s.std === 0) return null;
    return parseFloat(((cur - s.mean) / s.std).toFixed(2));
}

// Robust Z-score：0.6745 × (今日值 − Median) / IQR，抗離群值
function calcRobustZ(cur, key) {
    let s = getStats(key);
    if (!s || !s.iqr || s.iqr === 0) return null;
    return parseFloat((0.6745 * (cur - s.median) / s.iqr).toFixed(2));
}

// 百分位數：今日值落在歷史分布的哪個位置
const FIELD_MAP = {
    lick_time:'lick_time', lick_count:'lick_count',
    scratch_time:'scratch_time', scratch_count:'scratch_count',
    shake_count:'shake_count', walk_time:'walk_time', stop_time:'stop_time'
};
let _history = global.get('v2_daily_history','file') || [];

function calcPercentile(cur, key) {
    if (_history.length < 3) return null;
    let field = FIELD_MAP[key] || key;
    let vals  = _history.map(d => d[field] || 0).sort((a,b) => a - b);
    return parseFloat((vals.filter(v => v <= cur).length / vals.length * 100).toFixed(1));
}

// 偏差分（0~100）：依 Z-score 線性映射
// 0~1σ=正常(0~20), 1~2σ=輕度(20~50), 2~3σ=中度(50~80), >3σ=重度(80~100)
function calcDeviationScore(z) {
    if (z === null || z === undefined) return null;
    let az = Math.abs(z);
    if (az < 1.0) return parseFloat((az * 20).toFixed(1));
    if (az < 2.0) return parseFloat((20 + (az - 1.0) * 30).toFixed(1));
    if (az < 3.0) return parseFloat((50 + (az - 2.0) * 30).toFixed(1));
    return parseFloat(Math.min(100, 80 + (az - 3.0) * 10).toFixed(1));
}

// 為每個指標建立完整統計記錄
function buildRecord(cur, key) {
    let s  = getStats(key);
    let z  = calcZScore(cur, key);
    let rz = calcRobustZ(cur, key);
    let pc = calcPercentile(cur, key);
    return {
        today:           parseFloat((cur || 0).toFixed(2)),
        mean:            s.mean        || 0,
        median:          s.median      || 0,
        std:             s.std         || 0,
        rolling_mean:    s.rolling_mean|| 0,
        z_score:         z,
        robust_z:        rz,
        percentile:      pc,
        deviation_score: z !== null ? calcDeviationScore(z) : null
    };
}

let lick_t = td.lick    ? td.lick.time     : 0;
let lick_c = td.lick    ? td.lick.count    : 0;
let scr_t  = td.scratch ? td.scratch.time  : 0;
let scr_c  = td.scratch ? td.scratch.count : 0;
let shk_c  = td.shake   ? td.shake.count   : 0;
let walk_t = td.walk    ? td.walk.time     : 0;
let stop_t = td.stop    ? td.stop.time     : 0;

let dev = {
    // 第二層：自理行為統計偏差
    lick_duration:     buildRecord(lick_t, 'lick_time'),
    lick_frequency:    buildRecord(lick_c, 'lick_count'),
    scratch_duration:  buildRecord(scr_t,  'scratch_time'),
    scratch_frequency: buildRecord(scr_c,  'scratch_count'),
    head_shake:        buildRecord(shk_c,  'shake_count'),
    // 第一層：活動基線統計偏差
    walk_duration:     buildRecord(walk_t, 'walk_time'),
    inactive_duration: buildRecord(stop_t, 'stop_time'),

    overall:       0,
    baseline_days: bl.days_count || 0,
    confidence:    bl.confidence || 'Low',
    computed_at:   new Date().toISOString()
};

// 整體加權偏差分（各指標 deviation_score 加權平均，總和 = 1.0）
const WEIGHTS = { lick_duration:0.25, scratch_duration:0.25, head_shake:0.20, inactive_duration:0.15, walk_duration:0.15 };
let wSum = 0, wTotal = 0;
for (let [k, w] of Object.entries(WEIGHTS)) {
    let ds = dev[k] && dev[k].deviation_score;
    if (ds !== null && ds !== undefined) { wSum += ds * w; wTotal += w; }
}
dev.overall = wTotal > 0 ? parseFloat((wSum / wTotal).toFixed(1)) : 0;

// 向後相容：保留 sigma 欄位（舊版 Dashboard 可能引用）
dev.sigma = {
    lick_time:    dev.lick_duration.z_score,
    scratch_time: dev.scratch_duration.z_score,
    shake_count:  dev.head_shake.z_score,
    stop_time:    dev.inactive_duration.z_score
};

global.set('v2_deviation', dev);
msg.payload.deviation           = dev;
msg.payload.deviation_available = true;
msg.payload.baseline            = bl;
msg.payload.history_days        = _history.length;
return msg;

// ══════════════════════════════════════════════════════════════
//  行為偏差融合引擎 v3.1（Scientific Priority Enhancement）
//  ★ 三層研究架構：
//     ① Population Reference → 文獻參考值（不直接判斷）
//     ② Individual Baseline  → 個體化基線（真正判斷依據）
//     ③ Behavioral Deviation → 行為偏差輸出（非疾病診斷）
//  ★ 行為優先級：Class A（Critical）/ Class B（Supporting）/ Class C（Pattern）
//  ★ Class A Override Rule：高重要性行為允許單獨觸發警報（防止 False Negative）
//  ★ Single Behavior Critical Rule：舔舐/搔抓顯著偏離可獨立觸發偏差判定
//  文獻：Eckstein & Hart (2000), VAScat, ISFM Feline Behaviour Guidelines
// ══════════════════════════════════════════════════════════════

let cfg   = global.get('v2_user_settings','file') || {};
let data  = msg.payload;
let dev   = data.deviation;
let dist  = data.distribution || flow.get('v2_distribution') || {};
let rhythm= data.rhythm       || flow.get('v2_rhythm')       || {};
let mx    = data.v2_matrix    || global.get('v2_transition_matrix') || {};
let td    = data.v2_today     || {};
let bl    = data.baseline     || {};
try { if (!bl.computed_at) bl = global.get('v2_baseline','file') || {}; } catch(e) {}

// ── Population Reference（群體文獻參考值，不直接參與異常判斷）──
const POPULATION_REFERENCE = {
    lick_duration:    { mean_sec:3600, mean_display:'~60 min/day', source:'Eckstein & Hart (2000)', note:'健康室內成貓口腔梳理（群體參考，非異常門檻）' },
    scratch_duration: { mean_sec:60,   mean_display:'~1 min/day',  source:'Eckstein & Hart (2000)', note:'健康室內成貓搔抓梳理（群體參考，非異常門檻）' }
};

// ── 行為優先級分類（Behavior Priority Classification）──
// Class A: Critical Behaviour
//   - 與皮膚舒適度直接相關
//   - 允許單獨觸發警報（Single Behavior Critical Rule）
//   - Override Rule：Z≥2.5σ→Mild, Z≥3.0σ→Moderate, Z≥4.0σ→Severe
// Class B: Supporting Behaviour
//   - 輔助性偏差指標，提升警報 Confidence
//   - 不得獨立觸發警報
// Class C: Pattern Behaviour
//   - 整體行為模式分析（節律、轉移）
//   - 增強 Behavior Interpretation 品質
const CLASS_A_FEATURES = {
    lick_duration:    { weight:0.30, label:'Lick Duration',    threshold_mild:2.5, threshold_mod:3.0, threshold_severe:4.0, can_independently_trigger:true },
    lick_frequency:   { weight:0.15, label:'Lick Frequency',   threshold_mild:2.5, threshold_mod:3.0, threshold_severe:4.0, can_independently_trigger:true },
    scratch_duration: { weight:0.30, label:'Scratch Duration', threshold_mild:2.5, threshold_mod:3.0, threshold_severe:4.0, can_independently_trigger:true },
    scratch_frequency:{ weight:0.10, label:'Scratch Frequency',threshold_mild:2.5, threshold_mod:3.0, threshold_severe:4.0, can_independently_trigger:true }
};
const CLASS_B_FEATURES = {
    head_shake:        { weight:0.40, label:'Head Shake',        can_independently_trigger:false },
    walk_duration:     { weight:0.30, label:'Walk Duration',     can_independently_trigger:false },
    inactive_duration: { weight:0.30, label:'Inactive Duration', can_independently_trigger:false }
};
const LEVEL_ORDER = ['Normal','Mild Behavioral Deviation','Moderate Behavioral Deviation','Severe Behavioral Deviation'];

// Feature Metadata
const FEATURE_METADATA = {
    lick_duration: {
        feature_name:'Lick Duration', priority_class:'Class A (Critical)',
        scientific_meaning:'過度理毛可能與搔癢、疼痛、壓力等相關（VAScat, 2020）',
        population_ref:'健康成貓：約 60 min/day（Eckstein & Hart, 2000）',
        individual_ref:'此貓個體基線（請見 Individual Baseline 欄位）',
        monitoring_purpose:'監測是否偏離個體正常理毛模式，不代表疾病診斷',
        can_independently_trigger:true
    },
    scratch_duration: {
        feature_name:'Scratch Duration', priority_class:'Class A (Critical)',
        scientific_meaning:'搔抓行為可能與皮膚刺激、過敏、疼痛等相關',
        population_ref:'健康成貓：約 1 min/day（Eckstein & Hart, 2000）',
        individual_ref:'此貓個體基線（請見 Individual Baseline 欄位）',
        monitoring_purpose:'監測搔抓模式是否偏離個體基線，不代表過敏診斷',
        can_independently_trigger:true
    },
    lick_frequency: {
        feature_name:'Lick Frequency', priority_class:'Class A (Critical)',
        scientific_meaning:'理毛次數增加可能反映不適感',
        population_ref:'N/A（次數難以跨研究標準化）',
        individual_ref:'此貓個體基線（請見 Individual Baseline 欄位）',
        monitoring_purpose:'與 Lick Duration 共同評估理毛行為偏差',
        can_independently_trigger:true
    },
    scratch_frequency: {
        feature_name:'Scratch Frequency', priority_class:'Class A (Critical)',
        scientific_meaning:'搔抓次數可能反映皮膚刺激強度',
        population_ref:'N/A',
        individual_ref:'此貓個體基線（請見 Individual Baseline 欄位）',
        monitoring_purpose:'與 Scratch Duration 共同評估搔抓行為偏差',
        can_independently_trigger:true
    },
    head_shake: {
        feature_name:'Head Shake Frequency', priority_class:'Class B (Supporting)',
        scientific_meaning:'頻繁甩頭可能與耳部不適、耳蟎、耳道感染相關',
        population_ref:'偶爾甩頭屬正常範圍，無固定群體參考值',
        individual_ref:'此貓個體基線（請見 Individual Baseline 欄位）',
        monitoring_purpose:'輔助評估整體偏差程度，不可獨立觸發警報',
        can_independently_trigger:false
    },
    walk_duration: {
        feature_name:'Walk Duration', priority_class:'Class B (Supporting)',
        scientific_meaning:'行走時間代表整體活動量，減少可能代表不適',
        population_ref:'因個體差異大，無固定群體參考值',
        individual_ref:'此貓個體基線（請見 Individual Baseline 欄位）',
        monitoring_purpose:'輔助評估活動基線偏差',
        can_independently_trigger:false
    },
    inactive_duration: {
        feature_name:'Inactive Duration', priority_class:'Class B (Supporting)',
        scientific_meaning:'靜止時間過長可能代表低活力或不適',
        population_ref:'因個體差異大，無固定群體參考值',
        individual_ref:'此貓個體基線（請見 Individual Baseline 欄位）',
        monitoring_purpose:'輔助評估活動基線偏差',
        can_independently_trigger:false
    }
};

// 若基線不足
if (!dev || !dev.computed_at) {
    let result = {
        behavior_deviation_score:0, behavior_status:'基線建立中', behavior_trend:'Insufficient Data',
        behavior_deviation_level:'Insufficient Data', score:0, level:'Insufficient Data',
        color:'#9e9e9e', emoji:'⏳',
        components:{ class_a:0,class_b:0,class_c:0,rhythm:0,transition:0,grooming:0,activity:0,distribution:0,frequency:0 },
        class_a_triggered:false, class_a_override:null,
        alerts:[],
        xai_explanation:{
            behavior_deviation:'Insufficient Data', top_contributors:[], class_a_triggered:false,
            interpretation:'基線資料不足，尚無法進行行為偏差分析。請持續運行系統至少 '+(bl.required_days||7)+' 天。',
            population_reference:POPULATION_REFERENCE,
            research_note:'本系統採用三層研究架構：Population Reference（群體文獻值）→ Individual Baseline（個體基線）→ Behavioral Deviation（行為偏差）。',
            disclaimer:'本系統僅監測行為偏差，不代表任何疾病診斷。'
        },
        population_reference:POPULATION_REFERENCE, confidence:bl.confidence||'Low',
        computed_at:new Date().toISOString()
    };
    global.set('v2_risk',result);
    msg.payload.risk=result; msg.payload.user_settings=cfg;
    msg.payload.v2_event_tags=(global.get('v2_event_tags','file')||[]).slice(-14);
    msg.payload.v2_daily_history=(global.get('v2_daily_history','file')||[]).slice(-30);
    msg.payload.v2_excluded_dates=global.get('v2_excluded_dates','file')||[];
    msg.payload.v2_insufficient=true;
    flow.set('v2_today_risk',{level:'Insufficient Data',score:0});
    return [msg, null];
}

function gz(key) { return dev[key]&&dev[key].z_score!=null?(dev[key].z_score||0):0; }

let z_lick_d = gz('lick_duration');
let z_lick_f = gz('lick_frequency');
let z_scr_d  = gz('scratch_duration');
let z_scr_f  = gz('scratch_frequency');
let z_shake  = gz('head_shake');
let z_walk   = gz('walk_duration');
let z_stop   = gz('inactive_duration');

// ── Class A Score（Critical Behaviour, 0~100）──
// 加權 Z-score 融合（4個 Class A 特徵，權重總和歸一化）
let classAWeightedZ = (Math.abs(z_lick_d)*0.30 + Math.abs(z_lick_f)*0.15 + Math.abs(z_scr_d)*0.30 + Math.abs(z_scr_f)*0.10) / 0.85;
let classAScore = Math.min(100, classAWeightedZ * 25);

// ── Class A Override Rule（Single Behavior Critical Rule）──
// 高重要性行為允許單獨觸發偏差判定，防止 False Negative
// 例：舔舐 +4σ，其他正常 → 仍觸發 Moderate Behavioral Deviation
let classAOverride = null;
let classADetails = {
    lick_duration:    { z:z_lick_d, abs_z:Math.abs(z_lick_d), triggered:false },
    lick_frequency:   { z:z_lick_f, abs_z:Math.abs(z_lick_f), triggered:false },
    scratch_duration: { z:z_scr_d,  abs_z:Math.abs(z_scr_d),  triggered:false },
    scratch_frequency:{ z:z_scr_f,  abs_z:Math.abs(z_scr_f),  triggered:false }
};
let maxClassAZ = Math.max(...Object.values(classADetails).map(d=>d.abs_z));

if      (maxClassAZ >= 4.0) { classAOverride = 'Severe Behavioral Deviation';   Object.keys(classADetails).forEach(k=>{ if(classADetails[k].abs_z>=4.0) classADetails[k].triggered=true; }); }
else if (maxClassAZ >= 3.0) { classAOverride = 'Moderate Behavioral Deviation'; Object.keys(classADetails).forEach(k=>{ if(classADetails[k].abs_z>=3.0) classADetails[k].triggered=true; }); }
else if (maxClassAZ >= 2.5) { classAOverride = 'Mild Behavioral Deviation';     Object.keys(classADetails).forEach(k=>{ if(classADetails[k].abs_z>=2.5) classADetails[k].triggered=true; }); }
let classATriggered = classAOverride !== null;

// ── Class B Score（Supporting Behaviour, 0~100）──
let classBWeightedZ = Math.abs(z_shake)*0.40 + Math.abs(z_walk)*0.30 + Math.abs(z_stop)*0.30;
let classBScore = Math.min(100, classBWeightedZ * 25);

// ── Class C Score（Pattern Behaviour, 0~100）──
let rhythmScore=0;
let night=rhythm['00-06']||{}, day06=rhythm['06-12']||{}, day12=rhythm['12-18']||{};
if(night.dominant==='scratch'||night.dominant==='lick') rhythmScore+=35;
if(night.dominant==='shake')                             rhythmScore+=30;
if(night.pct&&night.pct.scratch>20)                     rhythmScore+=25;
if(day06.pct&&day12.pct&&(day06.pct.walk||0)<10&&(day12.pct.walk||0)<10) rhythmScore+=20;
rhythmScore=Math.min(100,rhythmScore);

let transScore=0;
let lsc=(mx['lick->scratch']||0)+(mx['scratch->lick']||0);
let shch=mx['shake->shake']||0, stst=mx['stop->stop']||0;
const BL_LSC=5;
if(lsc>BL_LSC*3) transScore+=40; else if(lsc>BL_LSC*2) transScore+=25; else if(lsc>BL_LSC) transScore+=12;
if(shch>15) transScore+=30; else if(shch>8) transScore+=15;
if(stst>50) transScore+=20; else if(stst>30) transScore+=10;
transScore=Math.min(100,transScore);
let classCScore=Math.round((rhythmScore+transScore)/2);

// ── Weighted Evidence Fusion（加權多重證據融合）──
// Class A 主導（45%），Class B 輔助（25%），Class C 模式（30%）
let fusionScore=Math.round(classAScore*0.45 + classBScore*0.25 + classCScore*0.30);

// ── 最終偏差等級決策（Fusion + Class A Override 取較高者）──
function scoreToLevel(s){ if(s<20)return 'Normal'; if(s<45)return 'Mild Behavioral Deviation'; if(s<70)return 'Moderate Behavioral Deviation'; return 'Severe Behavioral Deviation'; }
let fusionLevel=scoreToLevel(fusionScore), finalLevel=fusionLevel;
if(classAOverride!==null){
    let fi=LEVEL_ORDER.indexOf(fusionLevel), oi=LEVEL_ORDER.indexOf(classAOverride);
    if(oi>fi) finalLevel=classAOverride;
}

// 若 Override 生效，調整分數至對應等級最低值
let deviationMinScore={Normal:0,'Mild Behavioral Deviation':20,'Moderate Behavioral Deviation':45,'Severe Behavioral Deviation':70};
let behaviorDeviationScore=Math.max(fusionScore, finalLevel!==fusionLevel?(deviationMinScore[finalLevel]||0):0);
let deviationLevel=finalLevel;
let behaviorStatus,behaviorTrend,statusColor,statusEmoji;
if(deviationLevel==='Normal')                       {behaviorStatus='行為正常';   behaviorTrend='穩定';   statusColor='#4caf50';statusEmoji='✅';}
else if(deviationLevel==='Mild Behavioral Deviation')   {behaviorStatus='輕度行為偏差';behaviorTrend='輕微偏離';statusColor='#ffa726';statusEmoji='⚠️';}
else if(deviationLevel==='Moderate Behavioral Deviation'){behaviorStatus='中度行為偏差';behaviorTrend='明顯偏離';statusColor='#ff7043';statusEmoji='🚨';}
else                                                     {behaviorStatus='重度行為偏差';behaviorTrend='顯著偏離';statusColor='#f44336';statusEmoji='🆘';}

// ── XAI Explainable Output ──
function sigmaLabel(z){
    let az=Math.abs(z),sign=z>=0?'+':'';
    if(az<1.0) return '正常範圍';
    if(az<2.0) return sign+z.toFixed(1)+'σ（輕微偏離）';
    if(az<3.0) return sign+z.toFixed(1)+'σ（明顯偏離）';
    return sign+z.toFixed(1)+'σ（高度偏離）';
}

let allContributors=[
    {feature:'lick_duration',   z:z_lick_d,priority:'A',label:'Lick Duration'},
    {feature:'scratch_duration',z:z_scr_d, priority:'A',label:'Scratch Duration'},
    {feature:'lick_frequency',  z:z_lick_f,priority:'A',label:'Lick Frequency'},
    {feature:'scratch_frequency',z:z_scr_f,priority:'A',label:'Scratch Frequency'},
    {feature:'head_shake',       z:z_shake, priority:'B',label:'Head Shake'},
    {feature:'inactive_duration',z:z_stop,  priority:'B',label:'Inactive Duration'},
    {feature:'walk_duration',    z:z_walk,  priority:'B',label:'Walk Duration'}
].sort((a,b)=>Math.abs(b.z)-Math.abs(a.z));

let topContributors=allContributors.map(c=>({
    feature:c.feature, label:c.label, priority_class:'Class '+c.priority,
    z_score:parseFloat(c.z.toFixed(2)), sigma_label:sigmaLabel(c.z),
    can_independently_trigger:!!(CLASS_A_FEATURES[c.feature]),
    metadata:FEATURE_METADATA[c.feature]||{}
}));

// 自動解釋文字（三層架構論文語言）
let abnormalA=topContributors.filter(c=>c.priority_class==='Class A'&&Math.abs(c.z_score)>=2.0);
let abnormalB=topContributors.filter(c=>c.priority_class==='Class B'&&Math.abs(c.z_score)>=2.0);
let allAbnormal=topContributors.filter(c=>Math.abs(c.z_score)>=1.5);
let interp;
if(allAbnormal.length===0){
    interp='今日各項行為指標均在個體正常波動範圍內（Z-score < 1.5σ）。\n行為模式與個體歷史基線一致，建議繼續觀察。';
} else {
    let lines=[];
    if(abnormalA.length>0){
        lines.push('【Class A 關鍵行為偏差】'+abnormalA.map(c=>c.label+'（'+c.sigma_label+'）').join('、')+'。');
        if(classATriggered&&finalLevel!==fusionLevel) lines.push('依 Class A Override Rule，此關鍵行為偏差觸發最低警報等級至「'+deviationLevel+'」。');
    }
    if(abnormalB.length>0) lines.push('【Class B 輔助行為偏差】'+abnormalB.map(c=>c.label+'（'+c.sigma_label+'）').join('、')+'，提升警報可信度。');
    lines.push('綜合行為偏差分：'+behaviorDeviationScore+'/100（Class A融合:'+Math.round(classAScore)+' | Class B融合:'+Math.round(classBScore)+' | Pattern:'+Math.round(classCScore)+'）。');
    lines.push('注意：本系統基於個體歷史基線判斷行為偏差，不代表疾病診斷。如有疑慮請諮詢獸醫。');
    interp=lines.join('\n');
}

let xaiExplanation={
    behavior_deviation:    deviationLevel,
    class_a_triggered:     classATriggered,
    class_a_override:      classAOverride,
    class_a_details:       classADetails,
    top_contributors:      topContributors,
    class_a_behaviors:     topContributors.filter(c=>c.priority_class==='Class A'),
    class_b_behaviors:     topContributors.filter(c=>c.priority_class==='Class B'),
    interpretation:        interp,
    population_reference:  POPULATION_REFERENCE,
    research_note:         '系統研究架構：①Population Reference（Eckstein&Hart,2000）→ 群體文獻值，僅供合理性驗證 ②Individual Baseline（個體化基線）→ 真正的異常判斷依據 ③Behavioral Deviation → 行為偏差輸出（非疾病診斷）',
    disclaimer:            '本系統依據個體歷史行為基線判斷偏差程度，不代表任何疾病診斷。如貓咪出現明顯異常，請諮詢獸醫。'
};

// 警報清單（Class A 允許獨立警報，標記 priority）
let alerts=[];
if(Math.abs(z_lick_d)>=2.0) alerts.push({type:'lick',    priority:'A',z:z_lick_d,can_independently_trigger:true, msg:'[Class A] Lick Duration '     +(z_lick_d>=0?'+':'')+z_lick_d.toFixed(1)+'σ vs 個體基線'});
if(Math.abs(z_scr_d) >=2.0) alerts.push({type:'scratch', priority:'A',z:z_scr_d, can_independently_trigger:true, msg:'[Class A] Scratch Duration '  +(z_scr_d >=0?'+':'')+z_scr_d.toFixed(1) +'σ vs 個體基線'});
if(Math.abs(z_lick_f)>=2.0) alerts.push({type:'lick_f',  priority:'A',z:z_lick_f,can_independently_trigger:true, msg:'[Class A] Lick Frequency '    +(z_lick_f>=0?'+':'')+z_lick_f.toFixed(1)+'σ vs 個體基線'});
if(Math.abs(z_scr_f) >=2.0) alerts.push({type:'scr_f',   priority:'A',z:z_scr_f, can_independently_trigger:true, msg:'[Class A] Scratch Frequency ' +(z_scr_f >=0?'+':'')+z_scr_f.toFixed(1) +'σ vs 個體基線'});
if(Math.abs(z_shake) >=2.0) alerts.push({type:'shake',    priority:'B',z:z_shake, can_independently_trigger:false,msg:'[Class B] Head Shake '        +(z_shake >=0?'+':'')+z_shake.toFixed(1) +'σ vs 個體基線'});
if(Math.abs(z_walk)  >=2.0) alerts.push({type:'activity', priority:'B',z:z_walk,  can_independently_trigger:false,msg:'[Class B] Walk Duration '     +(z_walk  >=0?'+':'')+z_walk.toFixed(1)  +'σ vs 個體基線'});
if(Math.abs(z_stop)  >=2.0) alerts.push({type:'inactive', priority:'B',z:z_stop,  can_independently_trigger:false,msg:'[Class B] Inactive Duration ' +(z_stop  >=0?'+':'')+z_stop.toFixed(1)  +'σ vs 個體基線'});
if(lsc>BL_LSC*2)             alerts.push({type:'transition',priority:'C',msg:'[Class C] Lick↔Scratch 切換 '+lsc+' 次（異常轉移模式）'});

let result={
    behavior_deviation_score:behaviorDeviationScore, behavior_status:behaviorStatus,
    behavior_trend:behaviorTrend, behavior_deviation_level:deviationLevel,
    score:behaviorDeviationScore, level:deviationLevel, color:statusColor, emoji:statusEmoji,
    components:{ class_a:Math.round(classAScore), class_b:Math.round(classBScore), class_c:Math.round(classCScore),
                 rhythm:Math.round(rhythmScore), transition:Math.round(transScore),
                 grooming:Math.round(classAScore), activity:Math.round(classBScore),
                 distribution:Math.round(classAScore), frequency:Math.round(classBScore) },
    class_a_triggered:classATriggered, class_a_override:classAOverride,
    class_a_details:classADetails, fusion_score:fusionScore,
    alerts, xai_explanation:xaiExplanation, feature_metadata:FEATURE_METADATA,
    population_reference:POPULATION_REFERENCE, confidence:bl.confidence||'Low',
    computed_at:new Date().toISOString()
};

global.set('v2_risk',result);
msg.payload.risk=result; msg.payload.user_settings=cfg;
msg.payload.v2_event_tags=(global.get('v2_event_tags','file')||[]).slice(-14);
msg.payload.v2_daily_history=(global.get('v2_daily_history','file')||[]).slice(-30);
msg.payload.v2_excluded_dates=global.get('v2_excluded_dates','file')||[];
msg.payload.v2_insufficient=global.get('v2_baseline_insufficient')||false;
let blAlert=global.get('v2_baseline_alert')||null;
if(blAlert){msg.payload.v2_baseline_alert=blAlert;global.set('v2_baseline_alert',null);}
let exclRejected=global.get('v2_exclude_rejected')||null;
if(exclRejected){msg.payload.v2_exclude_rejected=exclRejected;global.set('v2_exclude_rejected',null);}
flow.set('v2_today_risk',{level:deviationLevel,score:behaviorDeviationScore});

let NOTIFY_LEVEL=cfg.notify_level!=null?+cfg.notify_level:2;
let shouldNotify=NOTIFY_LEVEL===1?deviationLevel==='Severe Behavioral Deviation'
               :NOTIFY_LEVEL===3?deviationLevel!=='Normal'
               :(deviationLevel==='Moderate Behavioral Deviation'||deviationLevel==='Severe Behavioral Deviation');
return [msg, shouldNotify?msg:null];

let risk = msg.payload.risk || {};

let _dcfg = global.get('v2_user_settings','file') || {};
let _url  = _dcfg.discord_webhook || '';
if (!_url) { node.warn('Discord webhook URL 未設定，請在 P4 飼主設定中填入'); return null; }

let lastSent = flow.get('v2_last_discord_risk') || '';
let key = (risk.behavior_deviation_level||risk.level) + '|' + (risk.alerts||[]).map(a=>a.type).join(',');
if (lastSent === key) return null;
flow.set('v2_last_discord_risk', key);

let color = {
    'Normal':65280, 'Mild Behavioral Deviation':16776960,
    'Moderate Behavioral Deviation':16753920, 'Severe Behavioral Deviation':16711680,
    'Insufficient Data':8421504
}[risk.behavior_deviation_level||risk.level] || 16711680;

let xai     = risk.xai_explanation || {};
let topList = (xai.top_contributors || []).slice(0,5);
let topText = topList.length>0 ? topList.map(c=>'['+c.priority_class.replace('Class ','')+'] '+c.label+': '+c.sigma_label).join('\n') : '（基線不足）';

let fields = [
    { name:'🎯 行為偏差分',   value:String(risk.behavior_deviation_score||0)+'/100', inline:true },
    { name:'📊 偏差等級',     value:(risk.emoji||'')+' '+(risk.behavior_deviation_level||risk.level||'N/A'), inline:true },
    { name:'🔴 Class A 關鍵', value:String(risk.components?risk.components.class_a:0), inline:true },
    { name:'🔵 Class B 輔助', value:String(risk.components?risk.components.class_b:0), inline:true },
    { name:'🌙 節律/轉移',   value:String(risk.components?risk.components.class_c:0),  inline:true },
    { name:'📈 基線信心',     value:String(risk.confidence||'Low'), inline:true }
];
if (risk.class_a_triggered) {
    let triggeredFeatures = Object.entries(risk.class_a_details||{}).filter(([,d])=>d.triggered).map(([k])=>k.replace('_',' ')).join(', ');
    fields.push({ name:'🚨 Class A Override', value:'Override 觸發：'+triggeredFeatures+'\n判定等級提升至：'+(risk.class_a_override||''), inline:false });
}
fields.push({ name:'🔍 Top Contributors', value:topText, inline:false });
if (risk.alerts&&risk.alerts.length>0) {
    let classAAlerts = risk.alerts.filter(a=>a.priority==='A').map(a=>a.msg).join('\n');
    let classBAlerts = risk.alerts.filter(a=>a.priority!=='A').map(a=>a.msg).join('\n');
    if (classAAlerts) fields.push({ name:'🔴 Class A 偏差警報', value:classAAlerts, inline:false });
    if (classBAlerts) fields.push({ name:'🔵 Class B/C 輔助警報', value:classBAlerts, inline:false });
}
if (xai.interpretation) fields.push({ name:'💬 行為解釋', value:xai.interpretation.substring(0,400), inline:false });
fields.push({ name:'⚠️ 免責聲明', value:'本通知代表行為偏差，不代表疾病診斷。如有疑慮請諮詢獸醫。', inline:false });

msg.headers={'Content-Type':'application/json'};
msg.url=_url;
msg.payload={
    username:'Cat Behavior Monitor',
    embeds:[{
        title:(risk.emoji||'🔔')+' 行為偏差通知：'+(risk.behavior_deviation_level||risk.level),
        description:'個體化行為基線比較分析結果（Individualized Behavioral Deviation Monitoring）',
        color, fields,
        footer:{ text:new Date().toLocaleString('zh-TW') }
    }]
};
return msg;

// ══════════════════════════════════════════════════════════════
//  三層式個體化基線計算器 v3.1（Scientific Enhancement）
//  ★ 新增 Population Reference Layer（文獻參考值，僅供合理性驗證）
//  ★ 新增 Sanity Check（個體基線 vs 群體參考值的合理性比對）
//  ★ 三層研究架構：
//     Population Reference → Individual Baseline → Behavioral Deviation
//  文獻：Eckstein & Hart (2000), VAScat, ISFM Feline Behaviour Guidelines
// ══════════════════════════════════════════════════════════════

const _blCfg = global.get('v2_user_settings','file') || {};
const MIN_BASELINE_DAYS = _blCfg.baseline_days != null ? +_blCfg.baseline_days : 7;
const MIN_DAILY_SEC = 3600;
const REQUIRED_PERIODS = [];
const EWMA_ALPHA = 0.15;
const MAX_BASELINE_DAYS = Math.max(MIN_BASELINE_DAYS, 30);

// ── Population Reference（群體文獻參考值）──
// 來源：Eckstein & Hart (2000), VAScat Feline Grooming Study
// 用途：
//   1. 系統初始化與合理性驗證（Sanity Check）
//   2. Dashboard 顯示供飼主理解「群體正常值」
//   3. 【不得直接作為異常判斷門檻】
// 系統異常判斷依賴個體化基線（Individual Baseline），非此群體參考值
const POPULATION_REFERENCE = {
    lick_duration:    { mean_sec:3600, mean_display:'~60 min/day',  ci:'(SD 未明確報告)', source:'Eckstein & Hart (2000)', note:'健康室內成貓，口腔梳理（Oral Grooming）' },
    scratch_duration: { mean_sec:60,   mean_display:'~1 min/day',   ci:'(SD 未明確報告)', source:'Eckstein & Hart (2000)', note:'健康室內成貓，搔抓梳理（Scratch Grooming）' },
    head_shake:       { mean_display:'Rare',   source:'Clinical observation', note:'偶爾甩頭屬正常範圍，無固定參考值' },
    walk_duration:    { mean_display:'Varies', source:'Individual-dependent', note:'活動量因個體、年齡、環境差異大' }
};

let history = global.get('v2_daily_history', 'file') || [];

if (history.length < MIN_BASELINE_DAYS) {
    let alertMsg = '歷史資料不足（' + history.length + ' 天），尚需 ' + (MIN_BASELINE_DAYS - history.length) + ' 天才能建立基線。';
    node.warn(alertMsg);
    global.set('v2_baseline_alert', alertMsg);
    global.set('v2_baseline_insufficient', true);
    msg.payload = { error:'基線資料不足', current_days:history.length, required_days:MIN_BASELINE_DAYS, population_reference:POPULATION_REFERENCE };
    return msg;
}

let validDays = history.filter(d => {
    if ((d.monitoring_seconds || 0) < MIN_DAILY_SEC) return false;
    if (!d.periods) return true;
    return REQUIRED_PERIODS.every(p => d.periods[p] && d.periods[p].monitoring_sec > 300);
});

let v2Excluded = global.get('v2_excluded_dates', 'file') || [];
if (v2Excluded.length > 0) {
    let noExcl = validDays.filter(d => !v2Excluded.includes(d.date));
    if (noExcl.length >= MIN_BASELINE_DAYS) { validDays = noExcl; node.warn('排除 ' + v2Excluded.length + ' 天後基線有效天數：' + validDays.length); }
    else { node.warn('排除後有效天不足（' + noExcl.length + ' 天），維持原有天數'); }
}

if (validDays.length < MIN_BASELINE_DAYS) {
    let alertMsg = '有效資料（' + validDays.length + ' 天）少於基線設定天數（' + MIN_BASELINE_DAYS + ' 天）。\n請降低設定，或等待更多有效資料累積。';
    node.warn('基線有效天不足：' + alertMsg);
    global.set('v2_baseline_alert', alertMsg);
    global.set('v2_baseline_insufficient', true);
    msg.payload = { error:'基線有效天不足', current_days:validDays.length, required_days:MIN_BASELINE_DAYS };
    return msg;
}

validDays.sort((a, b) => new Date(a.date) - new Date(b.date));
let days = validDays.slice(-MAX_BASELINE_DAYS);

function calcConfidence(n) {
    if (n < 7)  return 'Low';
    if (n < 30) return 'Medium';
    return 'High';
}

function calcFullStats(vals) {
    let arr = vals.filter(v => v !== null && v !== undefined).map(Number);
    let n = arr.length;
    if (n === 0) return { mean:0,median:0,std:0,iqr:0,q1:0,q3:0,sample_count:0,rolling_mean:0,rolling_std:0,last_update:new Date().toISOString() };
    let sorted = [...arr].sort((a,b) => a - b);
    let mean   = arr.reduce((s,v) => s+v, 0) / n;
    let std    = Math.sqrt(arr.reduce((s,v) => s+Math.pow(v-mean,2),0)/n);
    let median = n%2===0 ? (sorted[n/2-1]+sorted[n/2])/2 : sorted[Math.floor(n/2)];
    let q1_idx=(n-1)*0.25, q3_idx=(n-1)*0.75;
    let q1=sorted[Math.floor(q1_idx)]+(q1_idx%1)*(sorted[Math.ceil(q1_idx)]-sorted[Math.floor(q1_idx)]);
    let q3=sorted[Math.floor(q3_idx)]+(q3_idx%1)*(sorted[Math.ceil(q3_idx)]-sorted[Math.floor(q3_idx)]);
    let ewma=arr[0];
    for(let i=1;i<n;i++) ewma=EWMA_ALPHA*arr[i]+(1-EWMA_ALPHA)*ewma;
    let ewmaArr=[arr[0]],cur=arr[0];
    for(let i=1;i<n;i++){cur=EWMA_ALPHA*arr[i]+(1-EWMA_ALPHA)*cur;ewmaArr.push(cur);}
    let rollVar=arr.map((v,i)=>Math.pow(v-ewmaArr[i],2)).reduce((s,v)=>s+v,0)/n;
    return { mean:parseFloat(mean.toFixed(2)),median:parseFloat(median.toFixed(2)),std:parseFloat(std.toFixed(2)),iqr:parseFloat((q3-q1).toFixed(2)),q1:parseFloat(q1.toFixed(2)),q3:parseFloat(q3.toFixed(2)),sample_count:n,rolling_mean:parseFloat(ewma.toFixed(2)),rolling_std:parseFloat(Math.sqrt(rollVar).toFixed(2)),last_update:new Date().toISOString() };
}

let layer1 = {
    walk_duration:     calcFullStats(days.map(d=>d.walk_time||0)),
    walk_count:        calcFullStats(days.map(d=>d.walk_count||0)),
    rest_duration:     calcFullStats(days.map(d=>d.rest_time||0)),
    inactive_duration: calcFullStats(days.map(d=>d.stop_time||0)),
    stop_count:        calcFullStats(days.map(d=>d.stop_count||0)),
    active_ratio:      calcFullStats(days.map(d=>{ let mon=d.monitoring_seconds||1; return parseFloat(((d.active_time||0)/mon*100).toFixed(2)); })),
    daily_monitoring:  calcFullStats(days.map(d=>d.monitoring_seconds||0))
};
let layer2 = {
    lick_frequency:       calcFullStats(days.map(d=>d.lick_count   ||0)),
    lick_duration:        calcFullStats(days.map(d=>d.lick_time    ||0)),
    scratch_frequency:    calcFullStats(days.map(d=>d.scratch_count||0)),
    scratch_duration:     calcFullStats(days.map(d=>d.scratch_time ||0)),
    head_shake_frequency: calcFullStats(days.map(d=>d.shake_count  ||0))
};
let layer3_hourly = {};
for (let p of ['00-06','06-12','12-18','18-24']) {
    layer3_hourly[p] = calcFullStats(days.map(d=>d.periods&&d.periods[p]?(d.periods[p].monitoring_sec||0):0));
}
let periodCoverage = {};
for (let p of ['00-06','06-12','12-18','18-24']) {
    let covered=days.filter(d=>d.periods&&d.periods[p]&&d.periods[p].monitoring_sec>300).length;
    periodCoverage[p]={ covered, total:days.length };
}
let metrics = {
    lick_count:    { mean:layer2.lick_frequency.mean,       std:layer2.lick_frequency.std,       median:layer2.lick_frequency.median,       iqr:layer2.lick_frequency.iqr },
    lick_time:     { mean:layer2.lick_duration.mean,        std:layer2.lick_duration.std,        median:layer2.lick_duration.median,        iqr:layer2.lick_duration.iqr },
    scratch_count: { mean:layer2.scratch_frequency.mean,    std:layer2.scratch_frequency.std,    median:layer2.scratch_frequency.median,    iqr:layer2.scratch_frequency.iqr },
    scratch_time:  { mean:layer2.scratch_duration.mean,     std:layer2.scratch_duration.std,     median:layer2.scratch_duration.median,     iqr:layer2.scratch_duration.iqr },
    shake_count:   { mean:layer2.head_shake_frequency.mean, std:layer2.head_shake_frequency.std, median:layer2.head_shake_frequency.median, iqr:layer2.head_shake_frequency.iqr },
    shake_time:    { mean:0,std:0,median:0,iqr:0 },
    walk_time:     { mean:layer1.walk_duration.mean,        std:layer1.walk_duration.std,        median:layer1.walk_duration.median,        iqr:layer1.walk_duration.iqr },
    walk_count:    { mean:layer1.walk_count.mean, std:layer1.walk_count.std, median:layer1.walk_count.median, iqr:layer1.walk_count.iqr },
    stop_time:     { mean:layer1.inactive_duration.mean,    std:layer1.inactive_duration.std,    median:layer1.inactive_duration.median,    iqr:layer1.inactive_duration.iqr },
    stop_count:    { mean:layer1.stop_count.mean, std:layer1.stop_count.std, median:layer1.stop_count.median, iqr:layer1.stop_count.iqr }
};

// ── Sanity Check（合理性驗證：個體基線 vs 群體文獻值）──
// 目的：提示可能的資料品質問題，不直接影響異常判斷
// 若個體基線大幅偏離文獻值，代表資料可能有問題（錄影時間、辨識精度等）
let sanityWarnings = [];
let lickMean = layer2.lick_duration.mean;   // 個體舔舐基線（秒/天）
let scrMean  = layer2.scratch_duration.mean; // 個體搔抓基線（秒/天）

// 舔舐合理範圍：0.5 ~ 6 × 群體參考值
if (lickMean > 6 * 3600) {
    sanityWarnings.push('Lick Duration 個體基線（' + (lickMean/60).toFixed(0) + ' min/day）遠超群體參考值（~60 min/day）。請確認錄影時間、辨識模型精度及資料品質。');
    node.warn('[Sanity] Lick baseline too high: ' + (lickMean/60).toFixed(0) + ' min/day vs ~60 min/day pop ref');
}
if (lickMean > 0 && lickMean < 0.5 * 3600) {
    sanityWarnings.push('Lick Duration 個體基線（' + (lickMean/60).toFixed(1) + ' min/day）遠低於群體參考值（~60 min/day）。監控時間可能不足或模型漏偵。');
    node.warn('[Sanity] Lick baseline too low: ' + (lickMean/60).toFixed(1) + ' min/day vs ~60 min/day pop ref');
}
// 搔抓合理範圍：0.1 ~ 10 × 群體參考值
if (scrMean > 10 * 60) {
    sanityWarnings.push('Scratch Duration 個體基線（' + (scrMean/60).toFixed(0) + ' min/day）遠超群體參考值（~1 min/day）。請確認辨識精度。');
    node.warn('[Sanity] Scratch baseline too high: ' + (scrMean/60).toFixed(1) + ' min/day vs ~1 min/day pop ref');
}

let confidence = calcConfidence(days.length);

let baseline = {
    computed_at:         new Date().toISOString(),
    days_count:          days.length,
    required_days:       MIN_BASELINE_DAYS,
    confidence:          confidence,
    required_periods:    REQUIRED_PERIODS,
    period_coverage:     periodCoverage,
    layer1, layer2, layer3_hourly, metrics,
    // 新增：群體參考值（供 Dashboard 顯示與合理性比較）
    population_reference: POPULATION_REFERENCE,
    // 新增：合理性驗證結果
    sanity_warnings: sanityWarnings,
    sanity_ok:       sanityWarnings.length === 0
};

try { global.set('v2_baseline', baseline, 'file'); } catch(e) { global.set('v2_baseline', baseline); }
global.set('v2_baseline_insufficient', false);
node.warn('基線計算完成：' + days.length + ' 天資料，信心等級：' + confidence + (sanityWarnings.length>0?' ⚠️ Sanity Warning':''));
msg.payload = baseline;
return msg;

let today  = global.get('v2_today', 'file') || {};
let hourly = global.get('v2_hourly') || {};
let date   = today.date || new Date().toLocaleDateString('zh-TW');

// 計算各時段的行為與監控秒數
const PERIOD_HOURS = {
    '00-06': ['00','01','02','03','04','05'],
    '06-12': ['06','07','08','09','10','11'],
    '12-18': ['12','13','14','15','16','17'],
    '18-24': ['18','19','20','21','22','23']
};
let periods = {};
for (let [name, hrs] of Object.entries(PERIOD_HOURS)) {
    let d = {walk:0,lick:0,scratch:0,shake:0,stop:0,monitoring_sec:0};
    for (let h of hrs) {
        let hd = hourly[h] || {};
        for (let b of ['walk','lick','scratch','shake','stop']) d[b] += (hd[b]||0);
        d.monitoring_sec += (hd.monitoring_sec || 0);
    }
    d.total = d.walk+d.lick+d.scratch+d.shake+d.stop;
    periods[name] = d;
}

let rec = {
    date,
    lick_count:    today.lick    ? today.lick.count    : 0,
    lick_time:     today.lick    ? today.lick.time     : 0,
    scratch_count: today.scratch ? today.scratch.count : 0,
    scratch_time:  today.scratch ? today.scratch.time  : 0,
    shake_count:   today.shake   ? today.shake.count   : 0,
    shake_time:    today.shake   ? today.shake.time    : 0,
    walk_count:    today.walk    ? today.walk.count    : 0,
    walk_time:     today.walk    ? today.walk.time     : 0,
    stop_count:    today.stop    ? today.stop.count    : 0,
    stop_time:     today.stop    ? today.stop.time     : 0,
    active_time:        today.active_time       || 0,
    rest_time:          today.rest_time         || 0,
    not_detected_time:  today.not_detected_time  || 0,
    monitoring_seconds: today.monitoring_seconds || 0,
    monitoring_hours:   parseFloat(((today.monitoring_seconds || 0) / 3600).toFixed(2)),
    cat_visible_seconds: Math.max(0, (today.monitoring_seconds || 0) - (today.not_detected_time || 0)),
    stop_ratio:    today.active_time > 0
        ? parseFloat(((today.stop ? today.stop.time : 0) / today.active_time).toFixed(3))
        : 0,
    periods,
    risk: flow.get('v2_today_risk') || null
};

let newDay = {
    date: new Date().toLocaleDateString('zh-TW'),
    walk:    {count:0,time:0}, lick:    {count:0,time:0},
    scratch: {count:0,time:0}, shake:   {count:0,time:0},
    stop:    {count:0,time:0},
    active_time:0, rest_time:0, not_detected_time:0, monitoring_seconds:0
};
global.set('v2_today',  newDay,  'file');
global.set('v2_hourly', {});
global.set('v2_transition_matrix', {});

const MIN_RECORD_SEC = 1800; // 一天至少要有 30 分鐘（1800 秒）的監控才納入歷史，避免幾乎沒開系統的天污染基線
if ((rec.monitoring_seconds || 0) < MIN_RECORD_SEC) {
    node.warn('今日監控時間不足（' + rec.monitoring_seconds + ' 秒），跳過歷史記錄');
    return null;
}

let history = global.get('v2_daily_history', 'file') || [];
history = history.filter(h => h.date !== date); // 同一天只保留最新一筆，避免重複污染基線
history.push(rec);
if (history.length > 90) history = history.slice(-90);
global.set('v2_daily_history', history, 'file');
node.warn('每日彙整完成：' + date + '，歷史 ' + history.length + ' 天');

msg.payload = rec;
return msg;

// 每次午夜觸發都重算基線（確保昨日資料納入後立即更新）
const _rCfg = global.get('v2_user_settings','file') || {};
const MIN_BASELINE_DAYS = _rCfg.baseline_days != null ? +_rCfg.baseline_days : 7;
let history = global.get('v2_daily_history', 'file') || [];
if (history.length < MIN_BASELINE_DAYS) {
    node.warn('歷史不足（' + history.length + ' 天），跳過基線計算');
    return null;
}
node.warn('午夜觸發基線更新');
return msg;

let dev  = global.get('v2_deviation') || {};
let risk = global.get('v2_risk')      || {};
if (!dev.computed_at) return null;

function getZ(key)  { return dev[key] && dev[key].z_score  != null ? (dev[key].z_score  || 0) : 0; }
function getDs(key) { return dev[key] && dev[key].deviation_score != null ? (dev[key].deviation_score || 0) : 0; }

msg.payload = {
    timestamp:                new Date().toLocaleString('zh-TW'),
    lick_z:                   getZ('lick_duration'),
    scratch_z:                getZ('scratch_duration'),
    shake_z:                  getZ('head_shake'),
    stop_z:                   getZ('inactive_duration'),
    overall_deviation:        dev.overall || 0,
    behavior_deviation_level: risk.behavior_deviation_level || risk.level || 'N/A',
    behavior_deviation_score: risk.behavior_deviation_score || risk.score || 0,
    confidence:               dev.confidence || 'Low'
};
return msg;

let todayDate = new Date().toLocaleDateString('zh-TW');
let today     = global.get('v2_today', 'file');
let savedDate = today ? today.date : null;

if (savedDate && savedDate !== todayDate) {
    const MIN_RECORD_SEC = 1800;
    let monSec = today.monitoring_seconds || 0;
    if (monSec >= MIN_RECORD_SEC) {
        let _hourly = global.get('v2_hourly') || {};
        const _PHRS = {'00-06':['00','01','02','03','04','05'],'06-12':['06','07','08','09','10','11'],'12-18':['12','13','14','15','16','17'],'18-24':['18','19','20','21','22','23']};
        let _periods = {};
        for (let [_n,_hs] of Object.entries(_PHRS)) {
            let _d={walk:0,lick:0,scratch:0,shake:0,stop:0,monitoring_sec:0};
            for (let _h of _hs) { let _hd=_hourly[_h]||{}; for (let _b of ['walk','lick','scratch','shake','stop']) _d[_b]+=(_hd[_b]||0); _d.monitoring_sec+=(_hd.monitoring_sec||0); }
            _d.total=_d.walk+_d.lick+_d.scratch+_d.shake+_d.stop; _periods[_n]=_d;
        }
        let rec = {
            date:          savedDate,
            lick_count:    today.lick    ? today.lick.count    : 0,
            lick_time:     today.lick    ? today.lick.time     : 0,
            scratch_count: today.scratch ? today.scratch.count : 0,
            scratch_time:  today.scratch ? today.scratch.time  : 0,
            shake_count:   today.shake   ? today.shake.count   : 0,
            shake_time:    today.shake   ? today.shake.time    : 0,
            walk_count:    today.walk    ? today.walk.count    : 0,
            walk_time:     today.walk    ? today.walk.time     : 0,
            stop_count:    today.stop    ? today.stop.count    : 0,
            stop_time:     today.stop    ? today.stop.time     : 0,
            active_time:        today.active_time       || 0,
            rest_time:          today.rest_time         || 0,
            monitoring_seconds: monSec,
            monitoring_hours:   parseFloat((monSec / 3600).toFixed(2)),
            stop_ratio: today.active_time > 0
                ? parseFloat(((today.stop ? today.stop.time : 0) / today.active_time).toFixed(3))
                : 0,
            risk: null,
            periods: _periods
        };
        let history = global.get('v2_daily_history', 'file') || [];
        history = history.filter(h => h.date !== savedDate);
        history.push(rec);
        if (history.length > 90) history = history.slice(-90);
        global.set('v2_daily_history', history, 'file');
        node.warn('[啟動] 已彙整前一天資料：' + savedDate + '（' + monSec + ' 秒）');
    } else {
        node.warn('[啟動] 前一天（' + savedDate + '）監控時間不足（' + monSec + ' 秒），跳過歷史記錄');
    }
    let newDay = {
        date: todayDate,
        walk:    {count:0,time:0}, lick:    {count:0,time:0},
        scratch: {count:0,time:0}, shake:   {count:0,time:0},
        stop:    {count:0,time:0},
        active_time:0, rest_time:0, not_detected_time:0, monitoring_seconds:0
    };
    global.set('v2_today',            newDay, 'file');
    global.set('v2_hourly',           {});
    global.set('v2_transition_matrix', {});
    node.warn('[啟動] 偵測到跨日舊資料（' + savedDate + '），已彙整並清除 → 今天：' + todayDate);
} else if (!savedDate) {
    node.warn('[啟動] 無歷史資料，全新啟動。');
} else {
    node.warn('[啟動] 日期吐合（' + todayDate + '），保留今日資料繼續累積。');
}
return null;

global.set('v2_today', null, 'file');
global.set('v2_hourly', {});
global.set('v2_transition_matrix', {});
node.warn('[手動重置] 所有 Node-RED 資料已清除，下次啟動將顯示「全新啟動」');
return null;

let action = msg.payload && msg.payload.action;

// ── 測試 Discord 通知 ──────────────────────────────────────────
if (action === 'test_discord') {
    let url = (msg.payload.discord_webhook || '').trim();
    if (!url) { node.warn('Discord URL 未填入，無法發送測試通知'); return [null, null]; }
    msg.headers = {'Content-Type':'application/json'};
    msg.url     = url;
    msg.payload = {
        username: 'Cat Health Monitor',
        embeds: [{
            title: '🔔 測試通知',
            description: 'Cat Health Monitor 系統測試訊息\n若看到此訊息，代表 Discord Webhook 設定正確！',
            color: 3066993,
            footer: {text: new Date().toLocaleString('zh-TW')}
        }]
    };
    return [null, msg];  // output 2 → 送到 Discord
}

// ── 儲存設定 ──────────────────────────────────────────────────
if (action === 'save_settings') {
    let s    = msg.payload.settings || {};
    let prev = global.get('v2_user_settings','file') || {};
    let validated = {
        baseline_days:   Math.min(14, Math.max(3,  parseInt(s.baseline_days) || 7)),
        lick_pct:        Math.min(50, Math.max(10, parseInt(s.lick_pct)      || 20)),
        scratch_pct:     Math.min(40, Math.max(5,  parseInt(s.scratch_pct)   || 15)),
        shake_pct:       Math.min(30, Math.max(3,  parseInt(s.shake_pct)     || 10)),
        stop_pct:        Math.min(80, Math.max(30, parseInt(s.stop_pct)      || 55)),
        lsc_count:       Math.min(30, Math.max(3,  parseInt(s.lsc_count)     || 10)),
        discord_webhook: (s.discord_webhook || '').trim(),
        notify_level:    Math.min(3, Math.max(1, parseInt(s.notify_level) || 2)),
        cat_name:        (s.cat_name  || '').trim().slice(0,20),
        cat_breed:       (s.cat_breed || '').trim().slice(0,30),
        cat_birth_year:  parseInt(s.cat_birth_year)  || 0,
        cat_birth_month: Math.min(12, Math.max(1, parseInt(s.cat_birth_month) || 1))
    };
    global.set('v2_user_settings', validated, 'file');
    node.warn('飼主設定已儲存：' + JSON.stringify(validated));

    // URL 或靈敏度有變更 → 清除 dedup
    if ((prev.discord_webhook !== validated.discord_webhook && validated.discord_webhook) ||
        prev.notify_level !== validated.notify_level) {
        flow.set('v2_last_discord_risk', '');
        node.warn('Discord 設定已更新，已重置通知去重快取');
    }

    // 任何設定儲存都觸發基線重算（確保天數或閾值變更後立即生效）
    node.warn('設定已儲存，觸發基線重算');
    msg.payload = {};
    return [msg, null];  // output 1 → 觸發基線重算
}

// ── 事件標記儲存 ──────────────────────────────────────────────────
if (action === 'save_event_tag') {
    let tags = msg.payload.tags || [];
    let note = (msg.payload.note || '').trim();
    let date = msg.payload.date || new Date().toLocaleDateString('zh-TW');
    if (tags.length === 0 && !note) return [null, null];
    let events = global.get('v2_event_tags', 'file') || [];
    events = events.filter(function(e){ return e.date !== date; });
    events.push({date: date, tags: tags, note: note});
    if (events.length > 90) events = events.slice(-90);
    global.set('v2_event_tags', events, 'file');
    node.warn('事件標記已儲存：' + date + ' [' + tags.join(',') + ']');
    return [null, null];
}

// ── 排除日期切換（立即觸發基線重算）────────────────────────────────
if (action === 'toggle_exclude_date') {
    let exDate = (msg.payload.date || '').trim();
    if (!exDate) return [null, null];
    let excluded = global.get('v2_excluded_dates', 'file') || [];
    let ei = excluded.indexOf(exDate);
    if (ei < 0) {  // 新增排除 → 先檢查剩餘有效天數
        let cfg = global.get('v2_user_settings', 'file') || {};
        let minDays = cfg.baseline_days != null ? +cfg.baseline_days : 7;
        let history = global.get('v2_daily_history', 'file') || [];
        let newExcluded = excluded.concat([exDate]);
        let validRemaining = history.filter(d =>
            (d.monitoring_seconds || 0) >= 3600 &&
            !newExcluded.includes(d.date)
        ).length;
        if (validRemaining < minDays) {
            let rejectMsg = '排除後剩餘有效天數（' + validRemaining + ' 天）將少於基線設定天數（' + minDays + ' 天），請先降低基線天數或等待更多資料累積';
            global.set('v2_exclude_rejected', rejectMsg);
            node.warn('阻擋排除：' + rejectMsg);
            return [null, null];
        }
    }
    if (ei >= 0) excluded.splice(ei, 1);  // 已排除 → 取消排除
    else excluded.push(exDate);             // 未排除 → 加入排除
    global.set('v2_excluded_dates', excluded, 'file');
    node.warn('排除日期更新：' + JSON.stringify(excluded));
    msg.payload = {};
    return [msg, null];  // output 1 → 觸發基線重算
}

return [null, null];

// 個體化基線計算器輸出的 baseline 物件是巢狀結構
// （baseline.metrics.lick_count.mean 這種路徑），但下游 CSV 節點的
// 欄位樣板原本寫的是扁平 key（lick_count_mean），兩者對不上，
// 導致 baseline.csv 每一列統計欄位其實都是空的，而且樣板還漏了
// walk_time/walk_count/stop_time/stop_count 四個指標。
//
// 這裡只做「攤平」，完全不改變基線計算本身的任何數值 —— 不動
// 個體化基線計算器的統計邏輯。

let bl = msg.payload;
if (!bl || !bl.metrics) {
    node.warn('基線資料不足（' + (bl && bl.current_days) + ' 天），略過本次 baseline.csv 寫入');
    return null;
}

let m = bl.metrics;
function flat(key) {
    let s = m[key] || {};
    return { mean: s.mean || 0, std: s.std || 0, median: s.median || 0, iqr: s.iqr || 0 };
}

let out = { computed_at: bl.computed_at, days_count: bl.days_count, confidence: bl.confidence };
const METRIC_KEYS = [
    'lick_count', 'lick_time', 'scratch_count', 'scratch_time',
    'shake_count', 'shake_time', 'walk_time', 'walk_count',
    'stop_time', 'stop_count',
];
for (let key of METRIC_KEYS) {
    let f = flat(key);
    out[key + '_mean']   = f.mean;
    out[key + '_std']    = f.std;
    out[key + '_median'] = f.median;
    out[key + '_iqr']    = f.iqr;
}

msg.payload = out;
return msg;

// 修正「飼主設定拉桿調整後儲存未正確套用（尤其基線天數）」：
// 儲存設定會正確寫入 global.v2_user_settings，也會正確觸發
// 個體化基線計算器重算（後端數值本身沒有算錯）。但個體化基線計算器
// 原本只有一條輸出接去 CSV 匯出節點，完全沒有接回 P4 面板——P4 只透過
// 「行為偏差融合引擎」那條即時（Python 資料觸發）的鏈路更新畫面。
// 兩條鏈路互相獨立，導致使用者存檔後，P4 面板（基線天數、指標表格、
// 設定滑桿）要等到下一次即時資料週期才會刷新，看起來像「沒套用」。
//
// 這裡不改個體化基線計算器的計算邏輯，只是在它算完之後，額外組一份
// P4 面板看得懂的 payload，直接回推過去，讓存檔後畫面立即更新。

let bl  = msg.payload;
let cfg = global.get('v2_user_settings', 'file') || {};
let dev = global.get('v2_deviation') || null;
let historyLen = (global.get('v2_daily_history', 'file') || []).length;

let out = {};
if (bl && bl.metrics) {
    out.baseline         = bl;
    out.v2_insufficient  = false;
} else {
    out.v2_insufficient  = true;
    out.required_days    = (bl && bl.required_days) || cfg.baseline_days || 7;
}
out.deviation           = dev;
out.user_settings       = cfg;
out.history_days        = historyLen;
out.v2_daily_history    = (global.get('v2_daily_history', 'file') || []).slice(-30);
out.v2_event_tags       = (global.get('v2_event_tags', 'file') || []).slice(-14);
out.v2_excluded_dates   = global.get('v2_excluded_dates', 'file') || [];

return { payload: out };
